local function isExist(table, value)
    for index, v in pairs(table) do
        if tostring(v) == tostring(value) then
            return index
        end
    end
    return nil
end

local TeamInfo = class("TeamInfo", GameInfo)

function TeamInfo:initKey()
    self:addKey("players", "", true)
    self:addKey("totalCount", "0", true)
    self:addKey("liveCount", "0", true)
    self:addKey("isHaveBed", "1", true)
    self:addKey("isWin", "0", true)
    for _, gainId in pairs(TeamGainType) do
        self:addKey(gainId, "0", true)
    end
end

function TeamInfo:addPlayer(userId)
    local userIds = self:getPlayerIds()
    if isExist(userIds, userId) then
        return
    end
    table.insert(userIds, tostring(userId))
    self:setValue("players", table.concat(userIds, "#"))
    self:setValue("totalCount", #userIds)
end

function TeamInfo:subPlayer(userId)
    local userIds = self:getPlayerIds()
    local index = isExist(userIds, userId)
    if index then
        table.remove(userIds, index)
        self:setValue("players", table.concat(userIds, "#"))
        self:setValue("totalCount", #userIds)
    end
end

function TeamInfo:getPlayerIds()
    local players = self:getValue("players")
    return StringUtil.split(players, "#")
end

function TeamInfo:isPlayerInTeam(userId)
    local userIds = self:getPlayerIds()
    local index = isExist(userIds, userId)
    if index then
        return true
    end
    return false
end

return TeamInfo